insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('e5022ffa-d48d-4b1d-93e5-74c0a0edd61f', '8eb93f96-081e-4639-a33d-8c6621096866', $$inleiding — TCP en het aerotoxisch syndroom$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context1.png$$,
   $$Het aerotoxisch syndroom is een aandoening die in verband wordt gebracht met regelmatig vliegen. Een van de mogelijke oorzaken van deze aandoening is verontreiniging van de lucht in het vliegtuig door minimale hoeveelheden tri-cresylfosfaat (TCP). TCP wordt toegevoegd aan de smeerolie van straalmotoren en kan via kleine lekkages in de lucht van het vliegtuig terechtkomen. In figuur 1 is de reactievergelijking gegeven van de vorming van TCP uit onder andere cresol.$$, 'inline'),
  ('26d15e1a-44e7-4ee8-98de-d033f911c5cf', '8eb93f96-081e-4639-a33d-8c6621096866', $$figuur 1 — vorming van TCP uit fosforylchloride en cresol$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context2.png$$,
   $$figuur 1: reactievergelijking van de vorming van TCP. Cl−P(=O)(Cl)−Cl (fosforylchloride) + 3 HO−C₆H₄−CH₃ (cresol) → TCP + 3 HCl. In TCP is het centrale fosforatoom (P=O) via zuurstofbruggen verbonden met drie cresylgroepen; de methylgroep staat bij elke cresylgroep op een andere positie ten opzichte van de zuurstofbrug (drie structuurisomeren van cresol).$$, 'inline'),
  ('faed9263-aa8a-48b3-88c8-bf419bbd05ce', '8eb93f96-081e-4639-a33d-8c6621096866', $$cresol is een mengsel van drie structuurisomeren$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context3.png$$,
   $$De reactie in figuur 1 is slechts een voorbeeld. Het gebruikte cresol is namelijk een mengsel van drie structuurisomeren met dezelfde naam van de hoofdketen.$$, 'inline'),
  ('aaccdd31-fec3-4373-8016-adf02b4db2ba', '8eb93f96-081e-4639-a33d-8c6621096866', $$fosforatoom in TCP heeft 4-omringing$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context4.png$$,
   $$Het fosforatoom in TCP heeft een 4-omringing. De ruimtelijke verdeling van de atoombindingen rondom het fosforatoom is vergelijkbaar met die rondom een koolstofatoom met 4-omringing.$$, 'inline'),
  ('60837e17-9446-40a7-a9b4-dbb737bc9b72', '8eb93f96-081e-4639-a33d-8c6621096866', $$omzetting TCP tot stof A en BChE-P$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context5.png$$,
   $$Een mogelijke oorzaak van de aandoening is een verandering in een belangrijk enzym in de lever. In de lever komt het enzym BChE voor, dat een rol speelt bij de hydrolyse van bepaalde esters. Wanneer het lichaam TCP opneemt, wordt een van de isomeren van TCP in de lever omgezet tot stof A (zie figuur 2). Vervolgens wordt in drie reacties een serine-eenheid van BChE omgezet tot een fosfoserine-eenheid. In het vervolg van deze opgave wordt de omgezette BChE aangeduid met BChE-P.$$, 'inline'),
  ('1b4208a0-56cb-414a-ac77-f16009683d0b', '8eb93f96-081e-4639-a33d-8c6621096866', $$figuur 2 — stof A via CBDP naar fosfoserine-eenheid$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context6.png$$,
   $$figuur 2: schema van de omzetting van stof A (een TCP-isomeer) tot de fosfoserine-eenheid in BChE-P, in drie reacties. Stof A (met drie cresylgroepen aan het fosforatoom) verliest in reactie 1 een cresolmolecuul en vormt de cyclische verbinding CBDP. In reactie 2 (met H₂O en de serine-eenheid R−OH als aangegeven reagentia) ontstaat uit CBDP het tussenproduct cresol−O−P(=O)(OH)−O−R, naast stof X. In reactie 3 wordt onder afsplitsing van het laatste cresolmolecuul (met H₂O) de uiteindelijke fosfoserine-eenheid HO−P(=O)(OH)−O−R in BChE-P gevormd.$$, 'inline'),
  ('1fdc9a09-16b3-4184-b927-ead3207d1755', '8eb93f96-081e-4639-a33d-8c6621096866', $$reactie 2 — aanval OH-groep serine op CBDP$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context7.png$$,
   $$Reactie 2 begint met een aanval van de OH-groep van een serine-eenheid op het fosforatoom in CBDP. Hierbij ontstaat onder meer stof X.$$, 'inline'),
  ('3cd8ff3d-be2d-4d1d-9715-fad2f82eff76', '8eb93f96-081e-4639-a33d-8c6621096866', $$onderzoek naar BChE-P in bloed (stappen 1-3)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context8.png$$,
   $$In een onderzoek kon de aanwezigheid van BChE-P in bloed worden aangetoond. Men volgde hierbij de volgende stappen:
1 afname van bloed bij gezonde mensen en bij mensen met klachten
2 isolatie van BChE uit bloed waarin eventueel BChE-P voorkomt
3 hydrolyse van BChE; hierbij worden korte peptideketens gevormd
Van het mengsel van peptideketens afkomstig uit stap 3 werden vervolgens massaspectra gemaakt. Uit de resultaten kon worden opgemaakt dat de omzetting van de serine-eenheid uitsluitend aantoonbaar is in peptideketen 1.$$, 'inline'),
  ('a1a926cf-b71c-47ac-9d1e-bbb30cf52bec', '8eb93f96-081e-4639-a33d-8c6621096866', $$peptideketen 1 — aminozuursequentie$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context9.png$$,
   $$Phe – Gly – Glu – Ser – Ala – Gly – Ala – Ala – Ser
(peptideketen 1)$$, 'inline'),
  ('048c966d-8e2b-4043-95d0-828159bcc6b8', '8eb93f96-081e-4639-a33d-8c6621096866', $$piek bij m/z = 794, verlies H⁺ bij ionisatie$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context10.png$$,
   $$In de massaspectra van zowel gezonde mensen als patiënten is bij m/z = 794 een piek te zien die afkomstig is van peptideketen 1. Bij de ionisatie in de massaspectrometer wordt een H⁺-ion afgesplitst van de ongeladen peptideketens die in stap 3 zijn gevormd.$$, 'inline'),
  ('fd98e697-73d1-4418-90dd-13034bb3c510', '8eb93f96-081e-4639-a33d-8c6621096866', $$uitwerkbijlage vraag 4 — tabel molecuulmassa''s aminozuren$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-context11.png$$,
   $$tabel met molecuulmassa's (in u) van de aminozuren: Ala 89, Leu 131, Arg 174, Lys 146, Asn 132, Met 149, Asp 133, Phe 165, Cys 121, Pro 115, Gln 146, Ser 105, Glu 147, Thr 119, Gly 75, Trp 204, His 155, Tyr 181, Ile 131, Val 117.$$, 'uitwerkbijlage'),

  ('2d314935-8b2f-4c75-bea8-12bae7b4eec5', '7e7ae10c-a948-4026-81f4-34df479317ca', $$hout, cellulose, lignine en glucomannan$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context1.png$$,
   $$Hout bevat vooral de biopolymeren cellulose en lignine. Bij de isolatie van cellulose voor bijvoorbeeld papier, komt een grote hoeveelheid lignine vrij. De stof lignine kent nog weinig toepassingen. In hout komen ook andere biopolymeren voor, zoals glucomannan. Glucomannan is een polysacharide, opgebouwd uit β-D-glucose en D-mannose. De structuur van een molecuul D-mannose is gelijk aan die van β-D-glucose, waarbij de stereochemie op C2 anders is. De koppeling tussen beide monosachariden vindt uitsluitend plaats via de OH-groepen op C1 en C4.$$, 'inline'),
  ('dfe1f67d-23d7-4f28-b1e2-c02954b3ef2b', '7e7ae10c-a948-4026-81f4-34df479317ca', $$cellulose — kristallijne gebieden door stapeling$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context2.png$$,
   $$Cellulose is een lineair ketenpolymeer van glucose. Cellulose kan door regelmatige stapeling van de ketens kristallijne gebieden vormen. Lignine (zie figuur 1) bevindt zich tussen de ketens van cellulose in hout.$$, 'inline'),
  ('c94fe45e-475c-4c07-b376-71b47a167b93', '7e7ae10c-a948-4026-81f4-34df479317ca', $$figuur 1 — structuur van lignine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context3.png$$,
   $$figuur 1: vertakte structuur van lignine, opgebouwd uit meerdere aromatische (fenylpropaan-achtige) eenheden die onderling zijn verbonden via ether- (C−O−C) en C−C-bindingen; de eenheden dragen OH-, OCH₃- en CH₂OH-groepen en zijn deels via vijfringen (furaan-achtige ringen) met elkaar verbonden.$$, 'inline'),
  ('64b91465-9f7d-4909-b494-c11cee09b501', '7e7ae10c-a948-4026-81f4-34df479317ca', $$kraft-proces — cellulose uit hout$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context4.png$$,
   $$Het kraft-proces is het meest gebruikte proces om cellulose te verkrijgen uit hout. Het kraft-proces omvat enkele stappen. Eerst wordt houtpulp met water en chemicaliën verhit, zodat de lignine gedeeltelijk wordt gehydrolyseerd. Daarna wordt cellulose afgescheiden van het mengsel van lignine en chemicaliën. Ten slotte wordt de cellulose gedroogd en de chemicaliën worden deels teruggewonnen. De benodigde warmte voor het drogen van cellulose wordt verkregen door de verbranding van de verkregen lignine. Hierbij wordt ook elektrische energie opgewekt. Het kraft-proces voldoet aan een aantal uitgangspunten van de groene chemie.$$, 'inline'),
  ('f06d7510-6b6c-41ac-8abd-65d2ab69160f', '7e7ae10c-a948-4026-81f4-34df479317ca', $$lignine in elektrochemische waterstofproductie — inleiding$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context5.png$$,
   $$De lignine kan mogelijk ook worden toegepast in de elektrochemische productie van waterstof. Deze verloopt efficiënter wanneer hierbij een hulpstof zoals lignine wordt gebruikt. In een onderzoek naar deze toepassing van lignine hebben onderzoekers twee afzonderlijke reacties uitgevoerd:$$, 'inline'),
  ('1982bb97-a201-457b-bd1e-76b08f3f1d3b', '7e7ae10c-a948-4026-81f4-34df479317ca', $$stap 1 en stap 2 — fosfomolybdeenzuur en elektrolyse$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context6.png$$,
   $$stap 1: Biomassa wordt gemengd met een oplossing van het sterke zuur fosfomolybdeenzuur (H₃PMo₁₂O₄₀ of H₃POM).
stap 2: Elektrolyse van het mengsel dat na enige tijd is ontstaan.
De opstelling en de optredende halfreacties zijn in figuur 2 schematisch weergegeven.$$, 'inline'),
  ('b698ce1c-1f49-412b-a118-a14055c1b624', '7e7ae10c-a948-4026-81f4-34df479317ca', $$verwijzing naar figuur 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context7.png$$,
   $$De opstelling en de optredende halfreacties zijn in figuur 2 schematisch weergegeven.$$, 'inline'),
  ('10999dbb-beb5-4420-99ec-6bbea3251bda', '7e7ae10c-a948-4026-81f4-34df479317ca', $$figuur 2 — opstelling stap 1 en stap 2 (elektrolyse)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context8.png$$,
   $$figuur 2: opstelling voor de twee stappen. Stap 1: in een bakje reageert biomassa met POM⁵⁻ tot diverse producten, waarbij POM⁵⁻ wordt omgezet tot POM³⁻. Stap 2: elektrolysecel met een C-elektrode en een Pt-elektrode, gescheiden door een membraan; aan de C-elektrode wordt POM³⁻ geoxideerd tot POM⁵⁻, aan de Pt-elektrode wordt H⁺ gereduceerd tot H₂.$$, 'inline'),
  ('12dd5ea3-e976-460e-abd3-e0447b031a59', '7e7ae10c-a948-4026-81f4-34df479317ca', $$experimentcondities — 10 mL, [POM³⁻] = 0,50 M$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context9.png$$,
   $$Bij elk experiment werd in stap 1 telkens 10 mL oplossing gebruikt waarin bij aanvang [POM³⁻] = 0,50 M.$$, 'inline'),
  ('147f0305-3f99-4ae4-b171-32e9f9adf6de', '7e7ae10c-a948-4026-81f4-34df479317ca', $$invloed temperatuur — verwijzing naar figuur 3$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context10.png$$,
   $$De invloed van de temperatuur op de reacties in stap 1 is onderzocht. In figuur 3 zijn de resultaten weergegeven.$$, 'inline'),
  ('fe835eb8-c9fd-4ce1-8164-b27cd4f074a9', '7e7ae10c-a948-4026-81f4-34df479317ca', $$figuur 3 — omzettingsgraad POM³⁻ tegen tijd, drie experimenten$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context11.png$$,
   $$figuur 3: grafiek van de omzettingsgraad van POM³⁻ (%) tegen de tijd (dagen), voor drie experimenten. Experiment 1 vertoont de snelste stijging (tot ongeveer 65% na 12 dagen), experiment 2 een gematigde stijging (tot ongeveer 25% na 12 dagen), en experiment 3 de traagste stijging (tot ongeveer 8% na 12 dagen).$$, 'inline'),
  ('29e36bb3-62b6-4c59-a0ad-88379bb89b7b', '7e7ae10c-a948-4026-81f4-34df479317ca', $$vanilline via gaschromatografie (figuur 4)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context12.png$$,
   $$In stap 1 en tijdens de elektrolyse ontstaan allerlei nuttige afbraakproducten van lignine. Met behulp van gaschromatografie is onder andere de vorming van vanilline (zie figuur 4) bewezen. Een monster van de aanwezige stoffen werd hiervoor in een polaire kolom ingespoten met decaan als referentiestof. figuur 4: structuurformule van vanilline (4-hydroxy-3-methoxybenzaldehyde): benzeenring met een HO-groep, een OCH₃-groep en een CH=O-groep (aldehydegroep).$$, 'inline'),
  ('6aac39dc-469f-4668-9de7-f0ad3b8b371a', '7e7ae10c-a948-4026-81f4-34df479317ca', $$ladingsoverdracht en ligninegehalte naaldhout$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-context13.png$$,
   $$In een experiment werd een maximale ladingsoverdracht van 18 mmol elektronen per gram lignine bereikt. De lignine was afkomstig van droog naaldhout met een gemiddeld ligninegehalte van 28 massa%.$$, 'inline'),

  ('162aba78-f556-445d-8737-7ce2e0679cc2', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$inleiding — geosmine, geur na regen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context1.png$$,
   $$Als na een langere periode van droogte in de zomer een regenbui valt, ruik je buiten een karakteristieke geur. Deze geur wordt mede veroorzaakt door de stof geosmine. Geosmine wordt geproduceerd door bepaalde bacteriën in de bodem. In figuur 1 zijn de volledige en de schematische structuurformule van (–)-geosmine weergegeven. Deze isomeer van geosmine is de enige stereo-isomeer die wordt gevormd door de bacteriën.$$, 'inline'),
  ('995306ad-ff41-4bce-a60e-b13b8032426f', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$figuur 1 — structuurformule (–)-geosmine + legenda$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context2.png$$,
   $$figuur 1: volledige en schematische structuurformule van (–)-geosmine: een bicyclisch (decaline-achtig) systeem van twee gefuseerde zesringen met een OH-groep, een CH₃-groep op het bruggenkoppunt en een tweede CH₃-groep op een ringkoolstofatoom, met stereochemische aanduidingen (wiggen/gestippelde lijnen) voor de ruimtelijke oriëntatie van de substituenten. Legenda: een volle wig geeft een binding aan die uit het papiervlak naar voren komt, een gestippelde wig een binding die naar achteren wijst.$$, 'inline'),
  ('e36e9d3a-9ad5-40a3-ae8d-f8365df4f089', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$spiegelbeeld van (–)-geosmine gesynthetiseerd$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context3.png$$,
   $$In het laboratorium is het spiegelbeeld van (–)-geosmine gesynthetiseerd.$$, 'inline'),
  ('206ce926-eec8-4ed2-9054-7217df44558a', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$biosynthese geosmine — verwijzing naar figuur 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context4.png$$,
   $$In het vervolg van deze opgave worden uitsluitend schematische structuurformules gebruikt. In figuur 2 is de biosynthese van geosmine weergegeven. Een deeltje FPP wordt door één enzym in twee stappen omgezet tot een molecuul geosmine.$$, 'inline'),
  ('3a82f3b4-cbad-462d-8844-03d6b3f6c490', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$figuur 2 — biosynthese FPP naar geosmine (stap 1 en 2)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context5.png$$,
   $$figuur 2: biosynthese van geosmine uit FPP in het enzym. FPP (een acyclische keten met een OP₂O₆³⁻-groep) verliest in stap 1 het ion P₂O₇⁴⁻ en vormt het carbokation A⁺, dat met H₂O reageert tot germacradienol (een bicyclisch tussenproduct met een tertiaire OH-groep), onder afsplitsing van H⁺. In stap 2 wordt germacradienol met H₂O omgezet tot geosmine, onder afsplitsing van stof X.$$, 'inline'),
  ('9ba4dc5a-9746-4d74-8156-7a6d97b95db5', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$stap 1 — vorming ion A⁺ (C₁₅H₂₅⁺)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context6.png$$,
   $$In stap 1 worden twee elektronenparen verplaatst waardoor het ion P₂O₇⁴⁻ wordt afgesplitst en zich ion A⁺ (C₁₅H₂₅⁺) vormt. Vervolgens reageert A⁺ door tot germacradienol. In de structuurformule van ion A⁺ bevindt zich een ring van 10 C-atomen met daarin twee dubbele bindingen.$$, 'inline'),
  ('db336535-ae12-4fa5-87eb-a51ca22aa4f0', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$mechanisme stap 2 volgens Cane — deuteriumlabel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context7.png$$,
   $$Het mechanisme van stap 2 is lang onduidelijk geweest. Om hierover duidelijkheid te krijgen, is in germacradienol een H-atoom vervangen door een D-atoom (²H). Het enzym produceert dan geosmine-D. Onderzoeker Cane presenteerde een mechanisme waarbij het D-atoom met elektronenpaar naar C3 wordt verplaatst (zie figuur 3).$$, 'inline'),
  ('1ae85b89-637e-439e-911f-7b41da66f87d', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$figuur 3 — mechanisme Cane, germacradienol-D naar geosmine-D$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context8.png$$,
   $$figuur 3: mechanisme van stap 2 volgens Cane. Germacradienol-D (met D-label en een tertiaire OH-groep) verliest onder invloed van H⁺ een proton van de alkeengroep en vormt met verplaatsing van elektronenparen een gesloten bicyclisch tussenproduct (met D op de brug); dit tussenproduct reageert met H₂O (onder afsplitsing van H⁺) tot geosmine-D, met de OH-groep op de brugkop en de CH₃-groep en het D-atoom op de aangegeven ringposities (2, 3, 4).$$, 'inline'),
  ('f67c5c29-11f6-40c1-bf74-2f093426e316', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$H⁺ gebonden en afgesplitst — vorming stof X$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context9.png$$,
   $$In beide stappen in figuur 3 wordt zowel een H⁺-ion gebonden als weer afgesplitst. Bij de omzetting van germacradienol-D tot geosmine-D wordt een molecuul van stof X gevormd.$$, 'inline'),
  ('bcd3f267-01d2-4239-9c40-b0d08e915a9e', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$mechanisme volgens Boland — alternatief$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context10.png$$,
   $$Dit mechanisme was volgens een ander wetenschappelijk team onder leiding van Boland niet juist. Zij stelden een ander mechanisme voor, waarin het D-atoom naar de linker zesring wordt verplaatst in plaats van naar de rechter. Massaspectrometrie gaf uiteindelijk uitsluitsel welk mechanisme het best past bij de vorming van geosmine-D.$$, 'inline'),
  ('6c3c87e1-ba61-4bd2-8fc8-cbc06ff7e43b', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$fragmentatie 1 en 2 — verwijzing naar figuur 4$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context11.png$$,
   $$In figuur 4 zijn de twee manieren weergegeven hoe het geosmine-D, dat volgens Cane wordt gevormd, na ionisatie fragmenteert in de massaspectrometer. Bij fragmentatie 1 worden in de linker ring twee C–C-bindingen verbroken. Hierbij worden pent-1-een en fragment-ion Y⁺ gevormd. Bij fragmentatie 2 worden op een vergelijkbare manier ook twee C–C-bindingen verbroken, maar dan in de rechter ring.$$, 'inline'),
  ('084c2baf-62fc-4206-8d7f-446f3444ed9c', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$figuur 4 — fragmentatie 1 en 2 van geosmine-D$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context12.png$$,
   $$figuur 4: massaspectrometrische fragmentatie van geosmine-D (met genummerde ringposities 1-4, CH₃-groep, OH-groep en D-atoom). Bij fragmentatie 1 breken twee C–C-bindingen in de linker ring, waarbij pent-1-een en fragment-ion Y⁺ (het overblijvende deel met een positief geladen zuurstof O⁺−H en het D-atoom) ontstaan. Bij fragmentatie 2 breken op vergelijkbare wijze twee C–C-bindingen in de rechter ring, waarbij fragment-ion Z⁺ (met O⁺−H) en een niet nader aangeduid neutraal deeltje (met stippellijn aangegeven) ontstaan.$$, 'inline'),
  ('55a2efb7-e83b-4cb4-8555-3b9fa5fd6198', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$beide fragmentaties treden op$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context13.png$$,
   $$Beide manieren van fragmenteren treden op.$$, 'inline'),
  ('52bb21fd-95b5-4e3c-af59-e8d396820cab', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$verwijzing naar figuur 5 (massaspectrum)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context14.png$$,
   $$Het massaspectrum van geosmine-D is weergegeven in figuur 5.$$, 'inline'),
  ('7089e245-cc4b-46e2-9cd8-a01a90675084', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$figuur 5 — massaspectrum geosmine-D$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context15.png$$,
   $$figuur 5: massaspectrum van geosmine-D (intensiteit in % op de y-as tegen m/z op de x-as, bereik 0–160). De hoogste piek (basispiek, 100%) ligt bij m/z ≈ 112; andere pieken zijn onder meer zichtbaar rond m/z ≈ 55, 68, 84, 97, 111 en 126.$$, 'inline'),
  ('472c8a6e-eca9-4cbf-970a-9efcd7bbc7b6', 'daa40d5b-06f7-4cb9-aa9a-1a250ad7ffab', $$fragment-ion Z⁺ — piek bij m/z = 126$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-geosmine-context16.png$$,
   $$Het fragment-ion Z⁺ is verantwoordelijk voor de piek bij m/z = 126 in het massaspectrum.$$, 'inline'),

  ('59b1eeb0-87c1-4c3c-a853-40a8615db3f7', '3f0912eb-7735-40a7-b466-c7670cf69622', $$inleiding — N₂O₄, R1: ammoniak + zuurstof$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context1.png$$,
   $$Distikstoftetraoxide (N₂O₄) is een sterke oxidator, die onder andere wordt gebruikt in raketmotoren. N₂O₄ ontstaat als bijproduct bij de productie van salpeterzuur (HNO₃). Door de toegenomen vraag naar N₂O₄ wordt onderzoek gedaan of het mogelijk is om salpeterzuurfabrieken om te bouwen naar N₂O₄-fabrieken. Op basis van het onderzoek werd een aangepast proces voorgesteld met twee reactoren. In reactor 1 (R1) reageert ammoniak met een overmaat zuurstof tot stikstofmono-oxide en waterdamp.$$, 'inline'),
  ('b9d895cc-dfca-49bd-a815-75f6a237f293', '3f0912eb-7735-40a7-b466-c7670cf69622', $$S1 scheidt water af, NO naar R2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context2.png$$,
   $$Het gasmengsel afkomstig uit R1 wordt in scheidingsruimte 1 (S1) gebracht, waar water volledig wordt afgescheiden. Het gevormde stikstofmono-oxide reageert vervolgens in reactor 2 (R2) met zuurstof tot stikstofdioxide, waarbij zich twee evenwichten instellen.$$, 'inline'),
  ('04aac773-86dd-443f-a4f9-71024c60556e', '3f0912eb-7735-40a7-b466-c7670cf69622', $$evenwicht 1 en evenwicht 2 in R2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context3.png$$,
   $$2 NO (g) + O₂ (g) ⇌ 2 NO₂ (g) (evenwicht 1)
2 NO₂ (g) ⇌ N₂O₄ (g) (evenwicht 2)$$, 'inline'),
  ('993eac21-2b2f-455b-8aff-f0b582a6dbd6', '3f0912eb-7735-40a7-b466-c7670cf69622', $$beide evenwichten naar rechts exotherm$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context4.png$$,
   $$De reactie naar rechts is voor beide evenwichten in R2 exotherm. Onderdeel van het onderzoek was de vraag hoe het rendement van de productie van N₂O₄ kan worden verhoogd door de druk en de temperatuur in R2 te variëren.$$, 'inline'),
  ('4e9e179d-3843-4f9b-81cb-08d4c7971e41', '3f0912eb-7735-40a7-b466-c7670cf69622', $$afscheiding N₂O₄ — blokschema fabriek$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context5.png$$,
   $$De uitstroom van R2 wordt in een scheidingsruimte gebracht, waar N₂O₄ in vloeibare vorm wordt afgescheiden van de rest van het gasmengsel. De onderzoekers hebben op basis van het onderzoek een mogelijk blokschema voorgesteld van een N₂O₄-fabriek.$$, 'inline'),
  ('b6497ddc-1c32-44f3-ac87-af987b4fc7a8', '3f0912eb-7735-40a7-b466-c7670cf69622', $$MMH als brandstof — figuur structuurformule$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context6.png$$,
   $$N₂O₄ kan in een raketmotor worden gebruikt als oxidator. De brandstof is hierbij bijvoorbeeld monomethylhydrazine (MMH, zie de figuur). figuur: structuurformule van monomethylhydrazine (MMH): H₂N−NH(CH₃), een N–N-binding met aan het ene stikstofatoom twee H-atomen en aan het andere stikstofatoom een H-atoom en een CH₃-groep.$$, 'inline'),
  ('281922ec-848a-48c5-a7e1-606c80065e8f', '3f0912eb-7735-40a7-b466-c7670cf69622', $$hypergool mengsel — reactie 1 en reactie 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context7.png$$,
   $$MMH en N₂O₄ vormen een zogeheten 'hypergool mengsel'. Dat is een mengsel dat spontaan ontbrandt als de stoffen worden gemengd. Onderzoek heeft uitgewezen dat er bij contact tussen MMH en N₂O₄ twee reacties verlopen. Eerst verloopt een ontstekingsreactie (reactie 1) die genoeg energie levert, zodat de uiteindelijke verbrandingsreactie (reactie 2) kan starten. In reactie 2 worden MMH en N₂O₄ omgezet tot stikstof, koolstofdioxide en waterdamp.$$, 'inline'),
  ('02c9b06c-5252-4b1d-b258-fad5f9419717', '3f0912eb-7735-40a7-b466-c7670cf69622', $$twee energiediagrammen, zelfde schaal$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context8.png$$,
   $$Op de uitwerkbijlage zijn twee energiediagrammen onvolledig weergegeven: een voor de ontstekingsreactie (reactie 1) en een voor de uiteindelijke verbrandingsreactie (reactie 2). Beide energiediagrammen zijn op dezelfde schaal weergegeven.$$, 'inline'),
  ('1f628146-a3c3-4df3-8b6e-2a1994f9b9c8', '3f0912eb-7735-40a7-b466-c7670cf69622', $$onderzoek jaren 60 — smeltpunt MMH$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context9.png$$,
   $$Bij onderzoek in de jaren 60 naar de ontstekingsreactie is de reactie tussen MMH en N₂O₄ onderzocht bij zeer lage temperaturen. MMH is vloeibaar bij de gebruikte temperaturen terwijl N₂O₄ vast is. Het smeltpunt van MMH is –52 °C.$$, 'inline'),
  ('e3f31d3f-ad00-4144-aa1c-f2d052cd0cc1', '3f0912eb-7735-40a7-b466-c7670cf69622', $$isomeren N₂O₄ — ONONO₂ bij ontstekingsreactie$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context10.png$$,
   $$Uit dit onderzoek volgde dat meerdere isomeren van N₂O₄ in het mengsel aanwezig waren en dat een van deze isomeren, ONONO₂, betrokken was bij de ontstekingsreactie. Door de koeling vonden vervolgreacties niet plaats en was men in staat de reactieproducten van de ontstekingsreactie te onderzoeken. Op de uitwerkbijlage is het ONONO₂-isomeer weergegeven samen met het MMH-molecuul waarmee het reageert. Verder zijn de reactieproducten van de ontstekingsreactie gegeven.$$, 'inline'),
  ('d0b39292-4538-4dc8-bc71-c25926f089cf', '3f0912eb-7735-40a7-b466-c7670cf69622', $$Apollo-incident — 11 g N₂O₄ in cabine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context11.png$$,
   $$In 1975 is er bijna een ongeluk gebeurd met een Apollo-ruimtevaartuig. Tijdens de terugkeer in de dampkring werd een luchtinlaat geopend, waardoor N₂O₄ in de cabine terechtkwam. De drie aanwezige astronauten konden op tijd een zuurstofmasker opzetten. Bij het incident is ongeveer 11 gram N₂O₄ in de cabine met een volume van 5,9 m³ terechtgekomen. Gehaltes van N₂O₄ boven de waarde 300 volume-ppm worden als levensgevaarlijk beschouwd. Het molair volume van een gas is 2,39·10⁻² m³ mol⁻¹.$$, 'inline'),
  ('5d6e8cc4-fe35-4e30-9599-e35286aeb1ca', '3f0912eb-7735-40a7-b466-c7670cf69622', $$uitwerkbijlage vraag 19 — tabel evenwichtsligging$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context12.png$$,
   $$tabel op de uitwerkbijlage bij vraag 19: lege tabel met kolommen 'evenwicht', 'hogere temperatuur' en 'hogere druk', met rijen voor evenwicht 1 en evenwicht 2, in te vullen met 'links' of 'rechts'.$$, 'uitwerkbijlage'),
  ('bc448a01-4f3b-43d8-b50c-a3cc22144bd7', '3f0912eb-7735-40a7-b466-c7670cf69622', $$uitwerkbijlage vraag 20 — blokschema N₂O₄-fabriek$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context13.png$$,
   $$blokschema op de uitwerkbijlage bij vraag 20: gedeeltelijk voorgesteld blokschema van de N₂O₄-fabriek, met instroom NH₃ en O₂ naar reactor R1 en een uitgaande stofstroom uit R1, met ruime witruimte om de overige reactoren, scheidingsruimtes, pijlen en stofstromen aan te vullen.$$, 'uitwerkbijlage'),
  ('259810cc-59df-42ca-b4c9-6ef3c30d627e', '3f0912eb-7735-40a7-b466-c7670cf69622', $$uitwerkbijlage vraag 22 — energiediagrammen reactie 1 en 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context14.png$$,
   $$twee onvolledige energiediagrammen op de uitwerkbijlage bij vraag 22, op dezelfde schaal: voor reactie 1 (ontsteking) en reactie 2 (verbranding), elk met de energie-as en aanduidingen 'beginstoffen', 'geactiveerde toestand' en 'producten' op de x-as; de energieniveaus van de geactiveerde toestand en van de producten ontbreken nog.$$, 'uitwerkbijlage'),
  ('b7da22e4-0730-46e6-9a0f-30bd0c00881f', '3f0912eb-7735-40a7-b466-c7670cf69622', $$uitwerkbijlage vraag 24 — ONONO₂ + MMH mechanisme$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-distikstoftetraoxide-context15.png$$,
   $$structuurformules op de uitwerkbijlage bij vraag 24: het ONONO₂-isomeer van N₂O₄ en het MMH-molecuul, met een pijl naar de reactieproducten van de ontstekingsreactie (een N-verbinding met een O=N-groep en een N–N-binding, plus HNO₃); niet-bindende elektronenparen en formele ladingen links van de pijl ontbreken nog en moeten worden aangevuld, evenals de pijlen die de verplaatsing van elektronenparen weergeven.$$, 'uitwerkbijlage');

insert into practice_questions (id, exercise_id, question_number, topics, question_image_url, question_text, context_block_ids) values
  ('56b2027e-7d77-4659-b78f-08209f589765', '8eb93f96-081e-4639-a33d-8c6621096866', 1,
   '[{"domain": "Materie", "subdomain": "Moleculaire structuur en ruimtelijke bouw"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-vraag1.png$$, $$Geef de systematische namen van deze drie structuurisomeren.$$, array['26d15e1a-44e7-4ee8-98de-d033f911c5cf', 'faed9263-aa8a-48b3-88c8-bf419bbd05ce']::uuid[]),
  ('dc5ca10e-a99c-48f1-a742-160282372d15', '8eb93f96-081e-4639-a33d-8c6621096866', 2,
   '[{"domain": "Materie", "subdomain": "Isomeren (cis-trans en spiegelbeeld)"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-vraag2.png$$, $$Leg uit welke vorm van stereo-isomerie kan optreden bij TCP.$$, array['26d15e1a-44e7-4ee8-98de-d033f911c5cf', 'aaccdd31-fec3-4373-8016-adf02b4db2ba']::uuid[]),
  ('a35be2e0-aea2-4a67-8ea1-6352f34f538e', '8eb93f96-081e-4639-a33d-8c6621096866', 3,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-vraag3.png$$, $$Teken de structuurformule van stof X.$$, array['60837e17-9446-40a7-a9b4-dbb737bc9b72', '1b4208a0-56cb-414a-ac77-f16009683d0b', '1fdc9a09-16b3-4184-b927-ead3207d1755']::uuid[]),
  ('8100946a-022e-4a04-97ec-1205e4c725b8', '8eb93f96-081e-4639-a33d-8c6621096866', 4,
   '[{"domain": "Rekenen en analyse", "subdomain": "Chromatografie en massaspectrometrie"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-vraag4.png$$, $$Leg uit met behulp van een berekening dat de piek bij m/z = 794 hoort bij peptideketen 1.
Gebruik hierbij gegevens uit de tabel op de uitwerkbijlage.$$, array['a1a926cf-b71c-47ac-9d1e-bbb30cf52bec', '048c966d-8e2b-4043-95d0-828159bcc6b8', 'fd98e697-73d1-4418-90dd-13034bb3c510']::uuid[]),
  ('d0925d62-b242-40a2-a2d7-3f0b3b2d24fc', '8eb93f96-081e-4639-a33d-8c6621096866', 5,
   '[{"domain": "Materie", "subdomain": "Moleculaire structuur en ruimtelijke bouw"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-tcp-en-het-aerotoxisch-syndroom-vraag5.png$$, $$Teken de structuurformule van het gedeelte ~ Glu – Ser – Ala ~ waarin de serine-eenheid is omgezet tot een fosfoserine-eenheid.$$, array['1b4208a0-56cb-414a-ac77-f16009683d0b', '1fdc9a09-16b3-4184-b927-ead3207d1755', 'a1a926cf-b71c-47ac-9d1e-bbb30cf52bec']::uuid[]),

  ('04d256b9-99ae-4c56-800d-09c3cc14ccea', '7e7ae10c-a948-4026-81f4-34df479317ca', 6,
   '[{"domain": "Materie", "subdomain": "Polymeren, legeringen en keramische materialen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2024-ii-lignine-nuttig-afval-vraag6.png$$, $$Teken de structuurformule van een gedeelte van een molecuul glucomannan. Dit gedeelte moet komen uit het midden van het molecuul en moet zijn ontstaan uit een molecuul D-mannose en een molecuul β-D-glucose.
− Gebruik de notatie die ook in het informatieboek wordt gehanteerd.
− Gebruik Binas-tabel 67F1 of ScienceData-tabel 13.1d.$$, array['2d314935-8b2f-4c75-bea8-12bae7b4eec5']::uuid[]),
